+        const portId = portKey.replace('__port__', '');
+        const value = data[portKey];
+        return {
+          ...n,
+          inputs: n.inputs.map(p => p.id === portId ? { ...p, value } : p),
+        };
+      }
+
+      return { ...n, data: { ...n.data, ...data } };
