+    setIsRunning(true);
+    setConsoleOpen(true);
+    const interpreter = new Interpreter(
+      nodes,
+      wires,
+      (entry) => setConsoleEntries(prev => [...prev, entry]),
+      (nodeId) => setActiveNodeId(nodeId),
+    );
+    interpreterRef.current = interpreter;
+    interpreter.run().then(() => {
+      setIsRunning(false);
+      setActiveNodeId(null);
+    });
+  }, [nodes, wires, isRunning]);
+
+  const handleStop = useCallback(() => {
+    interpreterRef.current?.stop();
+    setIsRunning(false);
+    setActiveNodeId(null);
+  }, []);
+
+  const handleClear = useCallback(() => {
+    if (isRunning) return;
+    setNodes([]);
+    setWires([]);
+    setSelectedNodeId(null);
+  }, [isRunning]);
+
+  const handleFitView = useCallback(() => {
+    setViewport({ x: 0, y: 0, zoom: 1 });
+  }, []);
+
+  const gridSize = 20 * viewport.zoom;
+  const gridOffsetX = viewport.x % gridSize;
+  const gridOffsetY = viewport.y % gridSize;
+
+    return (
+    <div style={{ display: 'flex', flexDirection: 'column', width: '100%', height: '100vh', position: 'relative' }}>
+      <Toolbar
+        onRun={handleRun}
+        onStop={handleStop}
+        onClear={handleClear}
+        onFitView={handleFitView}
+        isRunning={isRunning}
+        nodeCount={nodes.length}
+        wireCount={wires.length}
+        zoom={viewport.zoom}
+      />
+
+      <div style={{ display: 'flex', flex: 1, minHeight: 0, position: 'relative' }}>
+        <NodePalette />
+
+        <div style={{ display: 'flex', flexDirection: 'column', flex: 1, minWidth: 0, position: 'relative' }}>
+          <div
+            ref={boardRef}
+            style={{
+              flex: 1, position: 'relative', overflow: 'hidden',
+              cursor: panning ? 'grabbing' : dragging ? 'default' : 'grab',
+              backgroundImage: `radial-gradient(circle at ${gridOffsetX}px ${gridOffsetY}px, #1a1a2e 1px, transparent 1px)`,
+              backgroundSize: `${gridSize}px ${gridSize}px`,
+            }}
+            onMouseDown={handleBoardMouseDown}
+            onContextMenu={handleContextMenu}
+            onDrop={handleDrop}
+            onDragOver={(e) => { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; }}
+          >
+            <div
+              style={{
+                transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`,
+                transformOrigin: '0 0',
+                position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
+              }}
+            >
+              <WireLayer wires={wires} nodes={nodes} drawingWire={drawingWire} />
+
+              {nodes.map(node => (
+                <NodeComponent
+                  key={node.id}
+                  node={node}
+                  isActive={activeNodeId === node.id}
+                  isSelected={selectedNodeId === node.id}
+                  onMouseDown={handleNodeMouseDown}
+                  onPortMouseDown={handlePortMouseDown}
+                  onPortMouseUp={handlePortMouseUp}
+                  onNodeDataChange={handleNodeDataChange}
+                />
+              ))}
+            </div>
+
+            {/* Keyboard shortcuts hint */}
+            <div
+              style={{
+                position: 'absolute', bottom: 16, right: 16,
+                display: 'flex', alignItems: 'center', gap: 12,
+                padding: '6px 14px', borderRadius: 10,
+                fontSize: 10, color: '#475569', fontWeight: 500,
+                pointerEvents: 'none',
+                background: 'rgba(18, 18, 30, 0.7)',
+                backdropFilter: 'blur(12px)',
+                WebkitBackdropFilter: 'blur(12px)',
+                border: '1px solid rgba(255, 255, 255, 0.05)',
+              }}
+            >
+              <span>Pan: Middle Click / Empty Space</span>
+              <span>·</span>
+              <span>Zoom: Scroll</span>
+              <span>·</span>
+              <span>Delete: Select + Del</span>
+            </div>
+          </div>
+
+          <ConsolePanel
+            entries={consoleEntries}
+            onClear={() => setConsoleEntries([])}
+            isOpen={consoleOpen}
+            onToggle={() => setConsoleOpen(!consoleOpen)}
+          />
+        </div>
+      </div>
+
+      {contextMenu && (
+        <ContextMenu
+          x={contextMenu.x}
+          y={contextMenu.y}
+          onAddNode={handleContextAddNode}
+          onClose={() => setContextMenu(null)}
+        />
+      )}
+
+      {showTutorial && (
+        <Tutorial
+          nodes={nodes}
+          onComplete={() => setShowTutorial(false)}
+          onLoadDemo={() => {
+            const demo = createDemoGraph();
+            setNodes(demo.nodes);
+            setWires(demo.wires);
+          }}
+          onSkip={() => setShowTutorial(false)}
+        />
+      )}
+    </div>
+  );
+};
+export default App;
